import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_pkgs(data):
    result = {}
    for fmk in data.get('projects', []):
        proj = fmk['path'].split('/')[-1]
        for tf in fmk.get('frameworks', []):
            for pkg in tf.get('topLevelPackages', []):
                key = (proj, pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = get_pkgs(baseline)
a = get_pkgs(after)
all_keys = sorted(set(b) | set(a))
changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    if bv != av:
        changes.append((k[0], k[1], bv, av))
    else:
        unchanged.append((k[0], k[1], bv))

print('=== CHANGES ===')
for c in changes:
    print(f'  {c[0]:20s} {c[1]:40s} {c[2]:>10s} -> {c[3]}')
print(f'Total changes: {len(changes)}')
print()
print(f'=== UNCHANGED: {len(unchanged)} packages ===')
for u in unchanged:
    print(f'  {u[0]:20s} {u[1]:40s} {u[2]:>10s}')
"
